1	<script setup lang="ts">
2	import { ref, computed } from 'vue'
3	import { useRouter, useRoute } from 'vue-router'
4	import { useAuthStore } from '@/stores/auth'
5	import {
6	  ChatDotRound,
7	  Share,
8	  Guide,
9	  DocumentCopy,
10	  DataAnalysis,
11	  User,
12	  Fold,
13	  Expand,
14	  SwitchButton,
15	} from '@element-plus/icons-vue'
16	
17	const router = useRouter()
18	const route = useRoute()
19	const authStore = useAuthStore()
20	
21	const isCollapsed = ref(false)
22	const isMobile = ref(window.innerWidth < 768)
23	
24	window.addEventListener('resize', () => {
25	  isMobile.value = window.innerWidth < 768
26	  if (isMobile.value) {
27	    isCollapsed.value = true
28	  }
29	})
30	
31	const activeMenu = computed(() => {
32	  return route.path
33	})
34	
35	const menuItems = [
36	  { path: '/chat', icon: ChatDotRound, title: '智能问答' },
37	  { path: '/graph', icon: Share, title: '知识图谱' },
38	  { path: '/path', icon: Guide, title: '学习路径' },
39	  { path: '/snippets', icon: DocumentCopy, title: '代码片段' },
40	  { path: '/dashboard', icon: DataAnalysis, title: '学习仪表盘' },
41	]
42	
43	function handleMenuSelect(path: string) {
44	  router.push(path)
45	}
46	
47	function toggleCollapse() {
48	  isCollapsed.value = !isCollapsed.value
49	}
50	
51	function handleLogout() {
52	  authStore.logout()
53	}
54	
55	function goProfile() {
56	  router.push('/profile')
57	}
58	</script>
59	
60	<template>
61	  <el-container class="app-layout">
62	    <!-- Sidebar -->
63	    <el-aside :width="isCollapsed ? '64px' : '220px'" class="app-sidebar">
64	      <div class="sidebar-header">
65	        <div v-if="!isCollapsed" class="logo-text">
66	          <el-icon :size="24" color="#409eff"><ChatDotRound /></el-icon>
67	          <span class="logo-title">智能编程助手</span>
68	        </div>
69	        <div v-else class="logo-icon">
70	          <el-icon :size="24" color="#409eff"><ChatDotRound /></el-icon>
71	        </div>
72	      </div>
73	
74	      <el-menu
75	        :default-active="activeMenu"
76	        :collapse="isCollapsed"
77	        :collapse-transition="true"
78	        class="sidebar-menu"
79	        background-color="#304156"
80	        text-color="#bfcbd9"
81	        active-text-color="#409eff"
82	        @select="handleMenuSelect"
83	      >
84	        <el-menu-item v-for="item in menuItems" :key="item.path" :index="item.path">
85	          <el-icon><component :is="item.icon" /></el-icon>
86	          <template #title>{{ item.title }}</template>
87	        </el-menu-item>
88	      </el-menu>
89	
90	      <div class="sidebar-footer">
91	        <el-button
92	          :icon="isCollapsed ? Expand : Fold"
93	          text
94	          class="collapse-btn"
95	          @click="toggleCollapse"
96	        />
97	      </div>
98	    </el-aside>
99	
100	    <!-- Main -->
101	    <el-container class="main-container">
102	      <!-- Header -->
103	      <el-header class="app-header">
104	        <div class="header-left">
105	          <h3 class="page-title">{{ (route.meta.title as string) || '' }}</h3>
106	        </div>
107	        <div class="header-right">
108	          <el-dropdown trigger="click" @command="(cmd: string) => cmd === 'profile' ? goProfile() : handleLogout()">
109	            <div class="user-info">
110	              <el-avatar :size="32" :src="authStore.user?.avatar || undefined">
111	                <el-icon :size="16"><User /></el-icon>
112	              </el-avatar>
113	              <span v-if="!isMobile" class="username">{{ authStore.user?.username || '用户' }}</span>
114	            </div>
115	            <template #dropdown>
116	              <el-dropdown-menu>
117	                <el-dropdown-item command="profile">
118	                  <el-icon><User /></el-icon>
119	                  个人中心
120	                </el-dropdown-item>
121	                <el-dropdown-item command="logout" divided>
122	                  <el-icon><SwitchButton /></el-icon>
123	                  退出登录
124	                </el-dropdown-item>
125	              </el-dropdown-menu>
126	            </template>
127	          </el-dropdown>
128	        </div>
129	      </el-header>
130	
131	      <!-- Content -->
132	      <el-main class="app-main">
133	        <router-view />
134	      </el-main>
135	    </el-container>
136	  </el-container>
137	</template>
138	
